diagnostics_hook:
#!/bin/bash
INPUT=$(head -c 65536); FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // ""')
[[ "$FILE" != *.ts && "$FILE" != *.tsx ]] && { echo '{"decision":"approve"}'; exit 0; }
ERRORS=$(npx tsc --noEmit 2>&1 | grep -F "$FILE" | head -5)
[ -n "$ERRORS" ] && echo "TypeScript errors related to $FILE:" >&2 && echo "$ERRORS" >&2
echo '{"decision":"approve"}'
